from elasticsearch import Elasticsearch
from datetime import datetime
import logging

class CentralizedLogger:
    def __init__(self, es_host='localhost', es_port=9200):
        self.es = Elasticsearch([{'host': es_host, 'port': es_port}])
        self.index_name = "logs-{}".format(datetime.now().strftime("%Y.%m.%d"))
        self._create_log_index()
        
    def _create_log_index(self):
        if not self.es.indices.exists(index=self.index_name):
            mapping = {
                "mappings": {
                    "properties": {
                        "timestamp": {"type": "date"},
                        "level": {"type": "keyword"},
                        "message": {"type": "text"},
                        "module": {"type": "keyword"},
                        "function": {"type": "keyword"},
                        "line_number": {"type": "integer"}
                    }
                }
            }
            self.es.indices.create(index=self.index_name, body=mapping)
    
    def log(self, level, message, module=None, function=None, line_number=None):
        log_doc = {
            "timestamp": datetime.now(),
            "level": level,
            "message": message,
            "module": module,
            "function": function,
            "line_number": line_number
        }
        self.es.index(index=self.index_name, body=log_doc)
    
    def search_logs(self, query, size=100):
        search_body = {
            "query": {
                "multi_match": {
                    "query": query,
                    "type": "bool_prefix",
                    "fields": ["message", "module", "function"]
                }
            },
            "sort": [{"timestamp": {"order": "desc"}}],
            "size": size
        }
        result = self.es.search(index=self.index_name, body=search_body)
        return [hit["_source"] for hit in result["hits"]["hits"]]
    
    def aggregate_logs(self, field, size=10):
        agg_body = {
            "aggs": {
                "field_agg": {
                    "terms": {
                        "field": field,
                        "size": size
                    }
                }
            }
        }
        result = self.es.search(index=self.index_name, body=agg_body)
        return result["aggregations"]["field_agg"]["buckets"]

